// Parse data from ElevenLabs post-call webhook
// ElevenLabs webhook format matches GET /conversations/{id} response
const raw = $input.all()[0].json;

// Log all top-level keys for debugging
const topKeys = Object.keys(raw);

// ElevenLabs sends data at top level OR nested under body/data
const body = raw.body || raw.data || raw;

// conversation_id can be at top level or nested
const conversationId = body.conversation_id || raw.conversation_id || '';

// transcript is an array of {role, message, time_in_call_secs}
const transcript = body.transcript || raw.transcript || [];

// metadata contains call_duration_secs, start_time_unix_secs etc
const metadata = body.metadata || raw.metadata || {};

// analysis contains call_successful, transcript_summary etc
const analysis = body.analysis || raw.analysis || {};

// Format transcript as readable text for ChatGPT
let transcriptText = '';
transcript.forEach((entry, index) => {
  const role = entry.role === 'agent' ? 'KLIENT (AI)' : 'MAKLÉŘ (Uživatel)';
  const msg = entry.message || entry.text || '';
  transcriptText += `${role}: ${msg}\n\n`;
});

return [{
  json: {
    conversationId,
    transcript,
    transcriptText,
    transcriptLength: transcript.length,
    metadata,
    analysis,
    durationSeconds: metadata.call_duration_secs || 0,
    _debug_topKeys: topKeys,
    _debug_hasBody: !!raw.body,
    _debug_hasData: !!raw.data
  }
}];

// Parse JSON from ChatGPT response
const item = $input.all()[0].json;

// ChatGPT response can be in different fields depending on n8n version
const chatResponse = item.message?.content || item.text || item.content || JSON.stringify(item);

let analysis;
try {
  // Remove potential markdown code blocks
  let cleaned = chatResponse.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  const jsonMatch = cleaned.match(/\{[\s\S]*\}/);
  analysis = JSON.parse(jsonMatch ? jsonMatch[0] : cleaned);
} catch (e) {
  analysis = {
    overall_score: 50,
    strengths: ["Analýza nebyla k dispozici"],
    improvements: ["Zkuste hovor znovu"],
    filler_words: [],
    recommendations: ["Kontaktujte podporu, pokud problém přetrvává"],
    transcript_highlights: []
  };
}

// Also pass through the call ID from earlier
const callId = $node["Find Call in Supabase"].json.id || '';

return [{ json: { analysis, callId } }];

// Prepare transcript rows for Supabase insert
const transcript = $node["Parse Webhook Data"].json.transcript || [];
const highlights = $json.analysis.transcript_highlights || [];
const callId = $json.callId;

if (!callId) {
  return [{ json: { error: 'No call ID found' } }];
}

const rows = transcript.map((entry, index) => {
  const mins = Math.floor(index * 8 / 60);
  const secs = (index * 8) % 60;
  const timestamp = `${mins}:${secs.toString().padStart(2, '0')}`;

  const highlightEntry = highlights.find(h => h.index === index);
  const highlightValue = highlightEntry ? highlightEntry.highlight : null;

  return {
    json: {
      call_id: callId,
      speaker: entry.role === 'agent' ? 'ai' : 'user',
      text: entry.message || '',
      timestamp_label: timestamp,
      highlight: highlightValue,
      sort_order: index
    }
  };
});

// Return at least one item even if transcript is empty
return rows.length > 0 ? rows : [{ json: { call_id: callId, speaker: 'ai', text: 'Prázdný přepis', timestamp_label: '0:00', highlight: null, sort_order: 0 } }];
